module asyn_fifo(
    input wclk, rclk, wrstn, rrstn, winc, rinc,
    input [7:0] wdata,
    output wfull, rempty,
    output [7:0] rdata
);

parameter WIDTH = 8;
parameter DEPTH = 16;

reg [3:0] waddr_bin, raddr_bin;
reg [3:0] wptr, rptr;
reg [3:0] wptr_buff, rptr_buff;
wire wen, ren;

dual_port_RAM #(.WIDTH(WIDTH), .DEPTH(DEPTH)) ram (
    .wclk(wclk),
    .wenc(wen),
    .waddr(waddr_bin[$clog2(DEPTH)-1:0]),
    .wdata(wdata),
    .rclk(rclk),
    .renc(ren),
    .raddr(raddr_bin[$clog2(DEPTH)-1:0]),
    .rdata(rdata)
);

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        waddr_bin <= 0;
    end else if (winc) begin
        waddr_bin <= waddr_bin + 1;
    end
end
assign wptr[0] = waddr_bin[0];
assign wptr[1] = waddr_bin[1] ^ waddr_bin[0];
assign wptr[2] = waddr_bin[2] ^ waddr_bin[1];
assign wptr[3] = waddr_bin[3] ^ waddr_bin[2];
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        wptr_buff <= 0;
    end else if (winc) begin
        wptr_buff <= wptr;
    end
end
assign wfull = (wptr == {~rptr_buff[3], rptr_buff[2:0]});

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        raddr_bin <= 0;
    end else if (rinc) begin
        raddr_bin <= raddr_bin + 1;
    end
end
assign rptr[0] = raddr_bin[0];
assign rptr[1] = raddr_bin[1] ^ raddr_bin[0];
assign rptr[2] = raddr_bin[2] ^ raddr_bin[1];
assign rptr[3] = raddr_bin[3] ^ raddr_bin[2];
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rptr_buff <= 0;
    end else if (rinc) begin
        rptr_buff <= rptr;
    end
end
assign rempty = (rptr == wptr);

assign wen = winc && !wfull;
assign ren = rinc && !rempty;
endmodule
